import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Let's implement /api/proxy first
  app.get("/api/proxy", async (req, res) => {
    const targetUrl = req.query.url as string;
    if (!targetUrl) {
      return res.status(400).json({ error: "Missing 'url' query parameter." });
    }

    try {
      console.log(`[Proxy Server] Fetching: ${targetUrl}`);
      const response = await fetch(targetUrl, {
        headers: {
          "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
          "Accept": "application/json, text/plain, */*",
          "Accept-Language": "zh-TW,zh;q=0.9,en-US;q=0.8,en;q=0.7",
          "Referer": "https://mis.twse.com.tw/",
        },
      });

      if (!response.ok) {
        throw new Error(`Target server returned HTTP status ${response.status}`);
      }

      const contentType = response.headers.get("content-type") || "";
      const text = await response.text();

      // Ensure proper UTF-8 content response
      res.setHeader("Content-Type", contentType.includes("application/json") ? "application/json; charset=utf-8" : contentType);
      
      try {
        const parsed = JSON.parse(text);
        return res.json(parsed);
      } catch {
        return res.send(text);
      }
    } catch (error: any) {
      console.error(`[Proxy Server Error] Failed fetching ${targetUrl}:`, error.message);
      return res.status(500).json({ error: error.message });
    }
  });

  // Vite middleware for development
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`[Proxy Server] Running on http://localhost:${PORT}`);
  });
}

startServer().catch((err) => {
  console.error("Failed to start server:", err);
});
